/**
 * @param {string[]} patterns
 * @param {string} word
 * @return {number}
 */
var numOfStrings = function(patterns, word) {
    let res = 0;

    for (const pattern of patterns) {
        if (word.includes(pattern)) {
            res++;
        }
    }

    return res;
};

/**
 * @param {string[]} patterns
 * @param {string} word
 * @return {number}
 */
var numOfStrings = function(patterns, word) {
    const set = new Set();

    for (let i = 0; i < word.length; i++) {
        let s = '';

        for (let j = i; j < word.length; j++) {
            s += word[j];
            set.add(s);
        }
    }

    let res = 0;

    for (const pattern of patterns) {
        if (set.has(pattern)) {
            res++;
        }
    }

    return res;
};
